import {
  BrowserRouter,
  Routes,
  Route
} from 'react-router-dom';


// ======================================
// LOGIN PAGE
// ======================================

import LoginPage
from '../pages/LoginPage';


// ======================================
// TEACHER PAGES
// ======================================

import TeacherDashboard
from '../pages/TeacherDashboard';

import SubjectManagementPage
from '../pages/SubjectManagementPage';

import AddStudentPage
from '../pages/AddStudentPage';

import AddMarksPage
from '../pages/AddMarksPage';


// ======================================
// STUDENT PAGES
// ======================================

import StudentDashboard
from '../pages/StudentDashboard';

import StudentSubjects
from '../pages/StudentSubjects';

import StudentMarks
from '../pages/StudentMarks';


// ======================================
// COORDINATOR PAGES
// ======================================

import CoordinatorDashboard
from '../pages/CoordinatorDashboard';

import CoordinatorNotes
from '../pages/CoordinatorNotes';

import CreateTeacher
from '../pages/CreateTeacher';


// ======================================
// APP ROUTES
// ======================================

function AppRoutes() {

  return (

    <BrowserRouter>

      <Routes>

        {/* ====================================== */}
        {/* LOGIN */}
        {/* ====================================== */}

        <Route
          path="/"
          element={<LoginPage />}
        />


        {/* ====================================== */}
        {/* TEACHER ROUTES */}
        {/* ====================================== */}

        <Route
          path="/teacher-dashboard"
          element={
            <TeacherDashboard />
          }
        />

        <Route
          path="/subjects"
          element={
            <SubjectManagementPage />
          }
        />

        <Route
          path="/add-student"
          element={
            <AddStudentPage />
          }
        />

        <Route
          path="/add-marks"
          element={
            <AddMarksPage />
          }
        />


        {/* ====================================== */}
        {/* STUDENT ROUTES */}
        {/* ====================================== */}

        <Route
          path="/student-dashboard"
          element={
            <StudentDashboard />
          }
        />

        <Route
          path="/student-subjects"
          element={
            <StudentSubjects />
          }
        />

        <Route
          path="/student-marks"
          element={
            <StudentMarks />
          }
        />


        {/* ====================================== */}
        {/* COORDINATOR ROUTES */}
        {/* ====================================== */}

        <Route
          path="/coordinator-dashboard"
          element={
            <CoordinatorDashboard />
          }
        />

        <Route
          path="/coordinator-notes"
          element={
            <CoordinatorNotes />
          }
        />

        <Route
          path="/create-teacher"
          element={
            <CreateTeacher />
          }
        />


      </Routes>

    </BrowserRouter>

  );

}

export default AppRoutes;
